"""
This module represents the checkers board.
"""

class Board:
    def __init__(self):
        self.board = self._initialize_board()
        self.current_player = 'white'

    def _initialize_board(self):
        board = [['' for _ in range(8)] for _ in range(8)]
        for row in [0, 2]:
            for col in range(0, 8, 2):
                board[row][col] = 'W'
        for row in [5, 7]:
            for col in range(1, 9, 2):
                board[row][col] = 'B'
        return board

    def print_board(self):
        for row in self.board:
            print(' '.join(row))

    # Additional methods to handle moving pieces, capturing, and checking legal moves will be added here
```

