"""
This module manages the checkers game logic.
"""

from board import Board
from piece import Piece

class Game:
    def __init__(self):
        self.board = Board()

    def play_game(self):
        while True:
            self.board.print_board()
            move = input(f"Player {self.board.current_player}, enter your move (e.g., A1-B2): ")
